AfterScript.Source:
          import sailpoint.workflow.IdentityRequestLibrary;

          import sailpoint.object.ApprovalSet;
          import sailpoint.object.WorkItem;
          import sailpoint.object.WorkflowCase;
          import sailpoint.object.Form;
          import sailpoint.object.ProvisioningPlan.AccountRequest;
          import sailpoint.object.ProvisioningPlan.AttributeRequest;
          import sailpoint.util.GeneralException;

          import sailpoint.object.Comment;
          import sailpoint.object.WorkItem.State;
          import sailpoint.object.ApprovalItem;

        if (item == null) {
          return;
          }

          WorkItem.State state = item.getState();
          if (state != null && (state.equals(WorkItem.State.Rejected) || state.equals(WorkItem.State.Expired) || state.equals(WorkItem.State.Canceled))) {
            List approvalItems = approvalSet.getItems();
            if(null != approvalItems){
              for (ApprovalItem approvalItem : approvalItems) {
                if(null != approvalItem){
                approvalItem.reject();
                List listOfComments = approvalItem.getComments();
                approvalItem.add(new Comment("Auto reject item due to lack of approval", "system"));
                item.addComment("Auto reject item due to lack of approval", "system");
                item.setCompletionComments("Auto reject item due to lack of approval");
                }
              }
            }
          }

          
          // Assimilate all of the approvalItem changes into our gloval
          // approval set
          //
          ApprovalSet set = (ApprovalSet)item.get("approvalSet");
          if ( set != null ) {
          // Global completion comments will apply to each of the items
          // If there are completion comments append them
          // to any other completion comments, but typically its
          // one or the other
          String completionComments = item.getCompletionComments();
          Identity id = item.getOwner();
          String ownerName = null;
          if ( id != null ) {
          ownerName = id.getName();
          }
          approvalSet.assimilate(set, ownerName, completionComments, true);
          } else {
          throw new GeneralException("ApprovalSet not found in afterscript.");
          }

          // djs: this is kind of a hack, do I have alternatives?
          // come back to this
          // jsl: Yes, I think you want <Return name='workItemForm' to='approvalForm'/>
          Form form = (Form)item.get("workItemForm");
          if ( form != null ) {
          WorkflowCase c = wfcontext.getWorkflowCase();
          if ( c != null ) {
          c.put("approvalForm", form);
          }
          }

          // bug#9611 if we notice that the manager request was edited,
          // change the next approval
          if (approvalScheme == null ||
          approvalScheme.contains("manager") ||
          approvalScheme.contains("newManager")) {
          Form form = item.getForm();
          if (form != null) {
          Field field = form.getField("IIQ:manager");
          if (field != null) {
          String newManager = field.getValue();
          if (newManager != null) {
          Approval newApproval = null;
          if (approval != null) {
          Approval parent = approval.getParent();
          if (parent != null) {
          // find the one after us
          List approvals = parent.getChildren();
          if (approvals != null) {
          Approval prev = null;
          for (int i = 0 ; i < approvals.size() ; i++) {
          Approval a = (Approval)approvals.get(i);
          if (prev == approval) {
          newApproval = a;
          break;
          }
          else
          prev = a;
          }
          }
          }
          }

          // newApproval can be null if the user didn't start
          // with a manager or if the current manager requested
          // the change
          if (newApproval != null) {
          String oldManager = newApproval.getOwner();

          // If the managers aren't equal, this *could* be a manager change
          // or it could just be some other type of approval.
          if (!newManager.equals(oldManager)) {

          // Get the manager that was submitted in the plan.
          String planager = null;
          if (null == plan) {
          log.warn("Expected a plan variable in identity request " +
          "approval AfterScript.");
          }
          else {
          AccountRequest iiqReq = plan.getIIQAccountRequest();
          if (null != iiqReq) {
          AttributeRequest managerReq =
          iiqReq.getAttributeRequest("manager");
          if (null != managerReq) {
          planager = managerReq.getValue();

          // May have an ID or name, so load it to get the name.
          Identity manager =
          context.getObject(Identity.class, planager);
          if (null != manager) {
          planager = manager.getName();
          }
          }
          }
          }

          // If the newManager is the same as what was originally submitted
          // then we haven't really changed the manager ... the newApproval
          // was for a different type of approver (eg - securityOfficer).
          if ((null == planager) || !planager.equals(newManager)) {
          log.info("Changing new manager approval owner from " +
          oldManager + " to " + newManager);
          newApproval.setOwner(newManager);

          // The old owner could have been cached.  Clear it to
          // make sure this goes to the right guy.
          newApproval.setIdentity(null);
          }
          }
          }
          }
          }
          }
          }

          //
          // If they are all rejected mark the Approval Rejected.
          // This allows the Transition to execute once we
          // get a rejection.
          //
          if ( approvalSet.isAllRejected() ) {
          approval.setState(WorkItem.State.Rejected);
          }

          IdentityRequestLibrary.assimilateWorkItemApprovalSetToIdentityRequest(wfcontext, approvalSet);
          auditWorkItemOwnerHistory(item);
          auditWorkItemComments(item);
          auditDecisions(item);

InterceptorScript.Source:
          import sailpoint.object.Workflow;
          import java.text.DateFormat;
          import sailpoint.object.IdentityRequest;
          import sailpoint.object.WorkItem;
          import sailpoint.object.EmailTemplate;
          import sailpoint.object.NotificationConfig;
          import sailpoint.object.NotificationConfig.ReminderConfig;
          import sailpoint.object.NotificationConfig.EscalationConfig;
          import sailpoint.object.IdentityRequestItem;
          import sailpoint.object.Custom;
          import java.lang.String;
          import java.util.List;
          import java.util.ArrayList;
          import java.lang.Integer.parseInt;

          import java.util.concurrent.TimeUnit;

          if (method != null && method.equals(Workflow.INTERCEPTOR_OPEN_WORK_ITEM)) {
            if (workflow != null) {
              if(item != null && context != null){
          			long hours = 0;
								long firstReminder = 0;
          			long secondReminder = 0;
          			long thirdReminder = 0;
                long escalation = 0;
                long escalationFirstReminder = 0;
                long escalationSecondReminder = 0;
                Custom customObj = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
                List managerConfigs = new ArrayList(); 
                
          
          
 								if(null != customObj && null != customObj.get("WorkitemReminders")){
          
          				if(null != customObj.get("WorkitemReminders").get("FirstReminderHours"))
                  {
          					hours = Integer.parseInt(customObj.get("WorkitemReminders").get("FirstReminderHours"));
                  	firstReminder = hours * 60 * 60 *1000;
                  }
         					if(null != customObj.get("WorkitemReminders").get("SecondReminderHours"))
                  {
          					hours = Integer.parseInt(customObj.get("WorkitemReminders").get("SecondReminderHours"));
                  	secondReminder = hours * 60 * 60 *1000;
                  }
          				if(null != customObj.get("WorkitemReminders").get("ThirdReminderHours"))
                  {
          					hours = Integer.parseInt(customObj.get("WorkitemReminders").get("ThirdReminderHours"));
                  	thirdReminder = hours * 60 * 60 *1000;
                  }
         					if(null != customObj.get("WorkitemReminders").get("EscalationHours"))
                  {
          					hours = Integer.parseInt(customObj.get("WorkitemReminders").get("EscalationHours"));
                  	escalation = hours * 60 * 60 *1000;
                  }
         					if(null != customObj.get("WorkitemReminders").get("EscalationFirstReminderHours"))
                  {
          					hours = Integer.parseInt(customObj.get("WorkitemReminders").get("EscalationFirstReminderHours"));
                  	escalationFirstReminder = hours * 60 * 60 *1000;
                  }
          				if(null != customObj.get("WorkitemReminders").get("EscalationSecondReminderHours"))
                  {
          					hours = Integer.parseInt(customObj.get("WorkitemReminders").get("EscalationSecondReminderHours"));
                  	escalationSecondReminder = hours * 60 * 60 *1000;
                  }
          
                  ReminderConfig firstReminderConfig = new ReminderConfig();
                  firstReminderConfig.setEnabled(true);
                  firstReminderConfig.setMillis(firstReminder);
                  firstReminderConfig.setEmailTemplateName(customObj.get("WorkitemReminders").get("ReminderEmailtemplate"));
                  managerConfigs.add(firstReminderConfig);

                  ReminderConfig secondReminderConfig = new ReminderConfig();
                  secondReminderConfig.setEnabled(true);
                  secondReminderConfig.setMillis(secondReminder);
                  secondReminderConfig.setEmailTemplateName(customObj.get("WorkitemReminders").get("ReminderEmailtemplate"));
                  managerConfigs.add(secondReminderConfig);

                  ReminderConfig thridReminderConfig = new ReminderConfig();
                  thridReminderConfig.setEnabled(true);
                  thridReminderConfig.setMillis(thirdReminder);
                  thridReminderConfig.setEmailTemplateName(customObj.get("WorkitemReminders").get("ReminderEmailtemplate"));
                  managerConfigs.add(thridReminderConfig);

                  EscalationConfig escalationConfig = new EscalationConfig();
                  escalationConfig.setEnabled(true);
                  escalationConfig.setMillis(escalation);
                  escalationConfig.setEscalationRuleName(customObj.get("WorkitemReminders").get("EscalationRule"));
                  escalationConfig.setEmailTemplateName(customObj.get("WorkitemReminders").get("EscalationEmailtemplate"));
                  managerConfigs.add(escalationConfig);
          
         					ReminderConfig fourthReminderConfig = new ReminderConfig();
                  fourthReminderConfig.setEnabled(true);
                  fourthReminderConfig.setMillis(escalationFirstReminder);
                  fourthReminderConfig.setEmailTemplateName(customObj.get("WorkitemReminders").get("ReminderEmailtemplate"));
                  managerConfigs.add(fourthReminderConfig);
          
         					ReminderConfig fifthReminderConfig = new ReminderConfig();
                  fifthReminderConfig.setEnabled(true);
                  fifthReminderConfig.setMillis(escalationSecondReminder);
                  fifthReminderConfig.setEmailTemplateName(customObj.get("WorkitemReminders").get("ReminderEmailtemplate"));
                  managerConfigs.add(fifthReminderConfig);

                  NotificationConfig notifConfig = new NotificationConfig();
                  notifConfig.setEnabled(true);
                  notifConfig.setEscalationEnabled(true);
                  notifConfig.setRemindersEnabled(true);
                  Date currentDate = new Date();
                  notifConfig.setStartDate(currentDate);
                  long timeinMillis = currentDate.getTime();

                  int expirationDays = Integer.parseInt(customObj.get("WorkitemReminders").get("ExpirationDays"));
                  Date laterDate = new Date(timeinMillis + expirationDays * 24 * 3600 * 1000);
                  notifConfig.setEndDate(laterDate);
                  notifConfig.setConfigs(managerConfigs);
                  notifConfig.setEscalationMaxReminders(Integer.parseInt(customObj.get("WorkitemReminders").get("EscalationMaxReminders")));
                  item.setupNotificationConfig(context, null, notifConfig);
                  context.saveObject(item);
                  context.commitTransaction();


                  if (item != null) {
                    wfcontext.setVariable("workItemName", item.getId());
                    WorkItem workItem = context.getObjectById(WorkItem.class, item.getId());
                    if (workItem != null) {
                      String name = workItem.getName();
                    }
                  }
                  String hoursTillExpiration = customObj.get("WorkitemReminders").get("HoursTillExpiration");
                  int hoursTillExpirationInt = Util.atoi(hoursTillExpiration);
                  if (hoursTillExpirationInt > 0) {
                    int minutes = hoursTillExpirationInt * 60;
                    Date dateExp = Util.incrementDateByMinutes(new Date(), minutes);
                    if (item != null && item.getExpirationDate() == null && dateExp != null) {
                      item.setExpiration(dateExp);
                      context.saveObject(item);
                      context.commitTransaction();
                      if (item != null) {
                       wfcontext.setVariable("actualWorkItem", item);
                      }
										}
                  }
                }
              }
            }
          }

Script.Source:
        import sailpoint.api.ObjectUtil;
        import sailpoint.object.ApprovalSet;
        import sailpoint.object.ApprovalItem;
        import sailpoint.object.Filter;
        import sailpoint.object.Identity;
        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.AccountRequest;
        import sailpoint.object.ProvisioningPlan.AttributeRequest;
        import sailpoint.object.QueryOptions;

        List accountRequests = plan.getAccountRequests(ProvisioningPlan.APP_IIQ);

        if ( accountRequests != null && !accountRequests.isEmpty() && accountRequests.get(0) != null) {
        AccountRequest iiq = accountRequests.get(0);
        // Look for the name attribute
        boolean nameChanged = false;
        String idName = identityName;
        AttributeRequest name = iiq.getAttributeRequest("name");
        if ( name != null ) {
        String nameStr = Util.otoa(name.getValue());
        if ( nameStr != null ) {
        nameStr = nameStr.trim();
        // If they don't match this indicates a form
        // update changes the accountId
        if ( identityName.compareTo(nameStr) != 0 ) {
        // If this is a create request, then it is a new identity, and we need to
        // re-verify that the identity does not exist. This is validated at the form level so should never
        // happen in the normal course of events, but important to check in case of http request manipulation.
        if (AccountRequest.Operation.Create.equals(iiq.getOperation())) {
        QueryOptions qo = new QueryOptions();
        Filter filter  = Filter.or(Filter.eq("id", nameStr), Filter.ignoreCase(Filter.eq("name", nameStr)));
        qo.add(new Filter[]{filter});
        qo.addFilter(ObjectUtil.buildWorkgroupInclusiveIdentityFilter());
        int count = wfcontext.getSailPointContext().countObjects(Identity.class, qo);
        if (count > 0) {
        throw new GeneralException("User '"+ nameStr + "' already exists.");
        }
        }

        idName = nameStr;
        nameChanged = true;
        // update the plan with the new/correct account ID
        iiq.setNativeIdentity(idName);
        }
        }
        }
        Identity planIdentity = plan.getIdentity();
        if ( ( planIdentity == null ) || ( nameChanged ) ) {
        SailPointContext ctx = wfcontext.getSailPointContext();
        Identity stub = ctx.getObjectByName(Identity.class, idName);
        if ( stub == null ) {
        stub = new Identity();
        stub.setName(idName);
        }
        plan.setIdentity(stub);
        }

        //
        // Update the approval item with any changes that
        // were made during the approval process
        //
        if ( approvalSet != null ) {
        List approvalItems =  approvalSet.getItems();
        // in the default case there is always just one item for all the changes
        if ( Util.size(approvalItems) == 1 ) {
        // Re-flatten the attribute values so they are accurate when auditing changes
        // and notifying. The values may have been updated in the approvalForm.
        ApprovalItem item = approvalItems.get(0);
        List attrRequestFlat = flattenAttributeRequests(iiq.getAttributeRequests());
        if ( attrRequestFlat != null ) {
        item.setValue(attrRequestFlat);
        }
        if ( nameChanged ) {
        item.setNativeIdentity(idName);
        }
        }
        }
        }
        return plan;
